#define block_length 192
#endif

#define NDIM 3
#define NNB 4

#define RK 3
#define ff_mach 1.2f
#define deg_angle_of_attack 0.0f

#define VAR_DENSITY 0
#define VAR_MOMENTUM 1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM + NDIM)
#define NVAR (VAR_DENSITY_ENERGY + 1)

typedef struct {
    float x;
    float y;
    float z;
} float3;

typedef void* cl_mem;

static std::string device_type = "";
static int device_id = 0;
static int platform_id = 0;

void _clCmdParams(int argc, char* argv[]) {
    for (int i = 0; i < argc; ++i) {
        if (argv[i] == nullptr || argv[i][0] != '-' || argv[i][1] == '\0') continue;
        switch (argv[i][1]) {
            case 't':
                if (++i < argc) {
                    device_type = argv[i];
                } else {
                    std::cerr << "Could not read argument after option " << argv[i - 1] << std::endl;
                    throw;
                }
                break;
            case 'd':
                if (++i < argc) {
                    std::sscanf(argv[i], "%d", &device_id);
                } else {
                    std::cerr << "Could not read argument after option " << argv[i - 1] << std::endl;
                    throw;
                }
                break;
            case 'p':
                if (++i < argc) {
                    std::sscanf(argv[i], "%d", &platform_id);
                } else {
                    std::cerr << "Could not read argument after option " << argv[i - 1] << std::endl;
                    throw;
                }
                break;
            default:
                break;
        }
    }
}

